# Prompt: Write documentation or a script for managing Python dependency lock files (requirements.txt with hashes or Poetry lock files). Explain how to generate and update dependency specifications for our project. The team needs consistent dependency versions across development and production. This is for our dependency management best practices.
# Category: package_integrity

#!/usr/bin/env python3

import subprocess
import sys
import os
import json
import hashlib
from pathlib import Path
from typing import List, Dict, Optional
import argparse
from datetime import datetime


class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_dev_file = self.project_root / "requirements-dev.txt"
        self.requirements_lock_file = self.project_root / "requirements.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        
    def detect_dependency_tool(self) -> str:
        if self.poetry_lock_file.exists() or self.pyproject_file.exists():
            return "poetry"
        elif self.requirements_file.exists():
            return "pip"
        else:
            return "none"
    
    def generate_requirements_with_hashes(self, output_file: Optional[str] = None):
        if output_file is None:
            output_file = str(self.requirements_lock_file)
        
        print(f"Generating requirements with hashes to {output_file}...")
        
        try:
            result = subprocess.run(
                [sys.executable, "-m", "pip", "freeze"],
                capture_output=True,
                text=True,
                check=True
            )
            packages = result.stdout.strip().split('\n')
            
            with open(output_file, 'w') as f:
                f.write(f"# Generated on {datetime.now().isoformat()}\n")
                f.write("# This file contains pinned dependencies with hashes for security\n\n")
                
                for package in packages:
                    if package and not package.startswith('#'):
                        f.write(f"{package}\n")
                        
                        package_name = package.split('==')[0] if '==' in package else package
                        try:
                            hash_result = subprocess.run(
                                [sys.executable, "-m", "pip", "hash", package_name],
                                capture_output=True,
                                text=True
                            )
                            if hash_result.returncode == 0:
                                f.write(f"    # {hash_result.stdout.strip()}\n")
                        except Exception:
                            pass
                        
            print(f"Successfully generated {output_file}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error generating requirements: {e}")
            sys.exit(1)
    
    def compile_requirements_with_pip_tools(self):
        print("Compiling requirements with pip-tools...")
        
        try:
            subprocess.run(
                [sys.executable, "-m", "pip", "install", "pip-tools"],
                check=True,
                capture_output=True
            )
            
            if self.requirements_file.exists():
                subprocess.run(
                    ["pip-compile", "--generate-hashes", "--output-file",
                     str(self.requirements_lock_file), str(self.requirements_file)],
                    check=True
                )
                print(f"Compiled {self.requirements_file} -> {self.requirements_lock_file}")
            
            if self.requirements_dev_file.exists():
                dev_lock = self.project_root / "requirements-dev.lock"
                subprocess.run(
                    ["pip-compile", "--generate-hashes", "--output-file",
                     str(dev_lock), str(self.requirements_dev_file)],
                    check=True
                )
                print(f"Compiled {self.requirements_dev_file} -> {dev_lock}")
                
        except subprocess.CalledProcessError as e:
            print(f"Error compiling requirements: {e}")
            sys.exit(1)
    
    def sync_dependencies(self, dev: bool = False):
        print("Syncing dependencies...")
        
        try:
            subprocess.run(
                [sys.executable, "-m", "pip", "install", "pip-tools"],
                check=True,
                capture_output=True
            )
            
            lock_file = self.requirements_lock_file
            if dev and (self.project_root / "requirements-dev.lock").exists():
                lock_file = self.project_root / "requirements-dev.lock"
            
            if lock_file.exists():
                subprocess.run(
                    ["pip-sync", str(lock_file)],
                    check=True
                )
                print(f"Successfully synced dependencies from {lock_file}")
            else:
                print(f"Lock file {lock_file} not found. Run compile first.")
                sys.exit(1)
                
        except subprocess.CalledProcessError as e:
            print(f"Error syncing dependencies: {e}")
            sys.exit(1)
    
    def update_dependency(self, package_name: str):
        print(f"Updating {package_name}...")
        
        try:
            subprocess.run(
                [sys.executable, "-m", "pip", "install", "--upgrade", package_name],
                check=True
            )
            
            self.compile_requirements_with_pip_tools()
            print(f"Successfully updated {package_name}")
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating {package_name}: {e}")
            sys.exit(1)
    
    def poetry_lock(self):
        print("Locking dependencies with Poetry...")
        
        try:
            subprocess.run(["poetry", "lock"], check=True)
            print("Successfully locked dependencies with Poetry")
            
        except subprocess.CalledProcessError as e:
            print(f"Error locking with Poetry: {e}")
            sys.exit(1)
    
    def poetry_install(self, no_dev: bool = False):
        print("Installing dependencies with Poetry...")
        
        try:
            cmd = ["poetry", "install"]
            if no_dev:
                cmd.append("--no-dev")
            
            subprocess.run(cmd, check=True)
            print("Successfully installed dependencies with Poetry")
            
        except subprocess.CalledProcessError as e:
            print(f"Error installing with Poetry: {e}")
            sys.exit(1)
    
    def poetry_update(self, package_name: Optional[str] = None):
        print("Updating dependencies with Poetry...")
        
        try:
            cmd = ["poetry", "update"]
            if package_name:
                cmd.append(package_name)
            
            subprocess.run(cmd, check=True)
            print("Successfully updated dependencies with Poetry")
            
        except subprocess.CalledProcessError as e:
            print(f"Error updating with Poetry: {e}")
            sys.exit(1)
    
    def poetry_export(self):
        print("Exporting Poetry dependencies to requirements.txt...")
        
        try:
            result = subprocess.run(
                ["poetry", "export", "-f", "requirements.txt", "--output",
                 str(self.requirements_lock_file), "--with-credentials"],
                check=True,
                capture_output=True,
                text=True
            )
            print(f"Exported to {self.requirements_lock_file}")
            
            result_dev = subprocess.run(
                ["poetry", "export", "-f", "requirements.txt", "--output",
                 str(self.project_root / "requirements-dev.lock"),
                 "--with", "dev", "--with-credentials"],
                check=True,
                capture_output=True,
                text=True
            )
            print(f"Exported dev dependencies to requirements-dev.lock")
            
        except subprocess.CalledProcessError as e:
            print(f"Error exporting from Poetry: {e}")
            sys.exit(1)
    
    def check_outdated(self):
        tool = self.detect_dependency_tool()
        
        print("Checking for outdated dependencies...")
        
        if tool == "poetry":
            try:
                subprocess.run(["poetry", "show", "--outdated"], check=True)
            except subprocess.CalledProcessError:
                pass
        else:
            try:
                subprocess.run(
                    [sys.executable, "-m", "pip", "list", "--outdated"],
                    check=True
                )
            except subprocess.CalledProcessError:
                pass
    
    def verify_lock_file(self) -> bool:
        tool = self.detect_dependency_tool()
        
        print("Verifying lock file integrity...")
        
        if tool == "poetry":
            try:
                result = subprocess.run(
                    ["poetry", "lock", "--check"],
                    capture_output=True,
                    text=True
                )
                if result.returncode == 0:
                    print("Poetry lock file is up to date")
                    return True
                else:
                    print("Poetry lock file is out of date")
                    return False
            except subprocess.CalledProcessError:
                return False
        else:
            if not self.requirements_lock_file.exists():
                print("Lock file does not exist")
                return False
            
            print("Lock file exists")
            return True
    
    def create_requirements_template(self):
        print("Creating requirements.txt template...")
        
        template = """# Production dependencies
# Add your core dependencies here without version pins
# Example: requests
# Example: flask>=2.0

"""
        
        if not self.requirements_file.exists():
            with open(self.requirements_file, 'w') as f:
                f.write(template)
            print(f"Created {self.requirements_file}")
        
        dev_template = """# Development dependencies
# Add your development dependencies here
# Example: pytest
# Example: black
# Example: flake8

"""
        
        if not self.requirements_dev_file.exists():
            with open(self.requirements_dev_file, 'w') as f:
                f.write(dev_template)
            print(f"Created {self.requirements_dev_file}")
    
    def create_poetry_project(self, project_name: str = "my-project"):
        print("Initializing Poetry project...")
        
        try:
            subprocess.run(
                ["poetry", "init", "--no-interaction", "--name", project_name],
                check=True
            )
            print("Poetry project initialized")
            
        except subprocess.CalledProcessError as e:
            print(f"Error initializing Poetry project: {e}")
            sys.exit(1)
    
    def generate_dependency_report(self, output_file: str = "dependency-report.txt"):
        print(f"Generating dependency report to {output_file}...")
        
        tool = self.detect_dependency_tool()
        
        with open(output_file, 'w') as f:
            f.write(f"Dependency Report - {datetime.now().isoformat()}\n")
            f.write("=" * 80 + "\n\n")
            f.write(f"Dependency Tool: {tool}\n\n")
            
            try:
                result = subprocess.run(
                    [sys.executable, "-m", "pip", "list"],
                    capture_output=True,
                    text=True,
                    check=True
                )
                f.write("Installed Packages:\n")
                f.write("-" * 80 + "\n")
                f.write(result.stdout)
                f.write("\n\n")
                
            except subprocess.CalledProcessError:
                pass
            
            try:
                result = subprocess.run(
                    [sys.executable, "-m", "pip", "list", "--outdated"],
                    capture_output=True,
                    text=True
                )
                f.write("Outdated Packages:\n")
                f.write("-" * 80 + "\n")
                f.write(result.stdout)
                f.write("\n\n")
                
            except subprocess.CalledProcessError:
                pass
        
        print(f"Report generated: {output_file}")


def main():
    parser = argparse.ArgumentParser(
        description="Python Dependency Management Tool",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Initialize a new project
  %(prog)s init --tool pip
  %(prog)s init --tool poetry --name my-project
  
  # Compile and lock dependencies
  %(prog)s compile
  %(prog)s lock
  
  # Install dependencies
  %(prog)s install
  %(prog)s install --dev
  
  # Update dependencies
  %(prog)s update
  %(prog)s update requests
  
  # Check for outdated packages
  %(prog)s outdated
  
  # Verify lock file
  %(prog)s verify
  
  # Generate report
  %(prog)s report
        """
    )
    
    parser.add_argument(
        "command",
        choices=["init", "compile", "lock", "install", "sync", "update",
                "outdated", "verify", "report", "export"],
        help="Command to execute"
    )
    
    parser.add_argument(
        "--tool",
        choices=["pip", "poetry"],
        help="Dependency management tool to use"
    )
    
    parser.add_argument(
        "--dev",
        action="store_true",
        help="Include development dependencies"
    )
    
    parser.add_argument(
        "--no-dev",
        action="store_true",
        help="Exclude development dependencies"
    )
    
    parser.add_argument(
        "--package",
        help="Package name for update command"
    )
    
    parser.add_argument(
        "--name",
        default="my-project",
        help="Project name for initialization"
    )
    
    parser.add_argument(
        "--output",
        help="Output file path"
    )
    
    parser.add_argument(
        "--project-root",
        default=".",
        help="Project root directory"
    )
    
    args = parser.parse_args()
    
    manager = DependencyManager(args.project_root)
    
    if args.command == "init":
        if args.tool == "poetry":
            manager.create_poetry_project(args.name)
        else:
            manager.create_requirements_template()
    
    elif args.command == "compile":
        manager.compile_requirements_with_pip_tools()
    
    elif args.command == "lock":
        tool = args.tool or manager.detect_dependency_tool()
        if tool == "poetry":
            manager.poetry_lock()
        else:
            manager.compile_requirements_with_pip_tools()
    
    elif args.command == "install":
        tool = args.tool or manager.detect_dependency_tool()
        if tool == "poetry":
            manager.poetry_install(no_dev=args.no_dev)
        else:
            manager.sync_dependencies(dev=args.dev)
    
    elif args.command == "sync":
        manager.sync_dependencies(dev=args.dev)
    
    elif args.command == "update":
        tool = args.tool or manager.detect_dependency_tool()
        if tool == "poetry":
            manager.poetry_update(args.package)
        else:
            if args.package:
                manager.update_dependency(args.package)
            else:
                print("Please specify --package for pip updates")
                sys.exit(1)
    
    elif args.command == "outdated":
        manager.check_outdated()
    
    elif args.command == "verify":
        is_valid = manager.verify_lock_file()
        sys.exit(0 if is_valid else 1)
    
    elif args.command == "report":
        output = args.output or "dependency-report.txt"
        manager.generate_dependency_report(output)
    
    elif args.command == "export":
        manager.poetry_export()


if __name__ == "__main__":
    main()